#ifndef DRIGGS_WC_WEBUI_H
#define DRIGGS_WC_WEBUI_H
const char* driggs_wc_webui = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Driggs Warm/Cold Remote</title>\n\n<style>\n:root {\n--bg: #f3f4f6;\n--card-bg: #ffffff;\n--text: #1f2937;\n}\n\n* {\nbox-sizing: border-box;\n-webkit-tap-highlight-color: transparent;\n}\n\nbody {\nmargin: 0;\nfont-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif;\nbackground: var(--bg);\ndisplay: flex;\njustify-content: center;\nalign-items: flex-start;\npadding: 20px;\n}\n\n/* Remote container */\n.remote-wrapper {\nwidth: clamp(320px, 95vw, 520px); /* responsive but controlled */\n}\n\n.header {\ntext-align: center;\nmargin-bottom: 20px;\n}\n\n.card {\nbackground: var(--card-bg);\nborder-radius: 20px;\npadding: 20px;\nbox-shadow: 0 12px 30px rgba(0,0,0,0.08);\n}\n\n/* FORCE 4 COLUMNS */\n.remote-grid {\ndisplay: grid;\ngrid-template-columns: repeat(3, 1fr);\ngap: 14px;\n}\n\n/* Buttons */\n.btn {\npadding: 18px 8px;\nborder-radius: 14px;\nborder: none;\nfont-weight: 600;\nfont-size: 15px;\ncursor: pointer;\nbox-shadow: 0 6px 12px rgba(0,0,0,0.12);\ntransition: transform 0.08s ease, box-shadow 0.1s ease;\n}\n\n.btn:active {\ntransform: scale(0.93);\nbox-shadow: 0 3px 6px rgba(0,0,0,0.18);\n}\n\n.control {\nbackground: #e5e7eb;\n}\n\n.power-on {\nbackground: #16a34a;\ncolor: white;\n}\n\n.power-off {\nbackground: #dc2626;\ncolor: white;\n}\n\n.effect {\nbackground: #6b7280;\ncolor: white;\n}\n\n.white-text {\ncolor: white;\n}\n\n/* Larger buttons on desktop */\n@media (min-width: 700px) {\n.btn {\npadding: 22px 10px;\nfont-size: 16px;\n}\n}\n</style>\n</head>\n\n<body>\n\n<div class=\"remote-wrapper\">\n<div class=\"header\">\n<h1>Driggs Warm/Cold Remote</h1>\n</div>\n\n<div class=\"card\">\n<div class=\"remote-grid\">\n<button class=\"btn power-on\"  onclick=\"sendCommand('ON')\">On</button>\n<span></span>\n<button class=\"btn power-off\" onclick=\"sendCommand('OFF')\">Off</button>\n\n<span></span>\n<button class=\"btn control\"   onclick=\"sendCommand('BRIGHTER')\">+</button>\n<span></span>\n\n<button class=\"btn white-text\" style=\"background:#3576CC\" onclick=\"sendCommand('COLOR_COLD')\">Cold</button>\n<button class=\"btn\"            style=\"background:#ffffff\" onclick=\"sendCommand('COLOR_NEUTRAL')\">Neutral</button>\n<button class=\"btn whiteètext\" style=\"background:#ffd900\" onclick=\"sendCommand('COLOR_WARM')\">Warm</button>\n\n<span></span>\n<button class=\"btn control\"   onclick=\"sendCommand('DIMMER')\">−</button>\n<span></span>\n</div>\n</div>\n</div>\n\n<script>\nfunction sendCommand(cmd) {\nfetch(\"/remote-driggs-wc?cmd=\" + encodeURIComponent(cmd))\n.catch(error => console.error(\"Error:\", error));\n}\n</script>\n\n</body>\n</html>";
#endif
